+	qq(2) = -y*q(1) +   q(2) + r*q(3) + p*q(4);
+	qq(3) =  p*q(1) - r*q(2) +   q(3) + y*q(4);
+	qq(4) = -r*q(1) - p*q(2) - y*q(3) +   q(4);
